"use client";
import { useState, useEffect } from "react";
import { FaBars, FaTimes } from "react-icons/fa";
import { MdOutlineFileDownload } from "react-icons/md";

const Navbar = () => {
  const [nav, setNav] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const links = [
    { id: 1, link: "about" },
    { id: 2, link: "skills" },
    { id: 3, link: "projects" },
    { id: 4, link: "contact" },
  ];

  return (
    <nav
      className={`fixed w-full h-20 z-50 transition-all duration-300 ${
        scrolled ? "glass-nav" : "bg-transparent"
      }`}
    >
      <div className="flex justify-between items-center w-full h-full px-4 max-w-7xl mx-auto">
        <div>
          <h1 className="text-2xl font-bold tracking-tight cursor-pointer hover:text-blue-500 transition-colors duration-300">
            Shivam Sharma<span className="text-blue-500">.</span>
          </h1>
        </div>

        <div className="hidden md:flex items-center gap-8">
          <ul className="flex gap-8">
            {links.map(({ id, link }) => (
              <li
                key={id}
                className="capitalize font-medium text-slate-400 hover:text-white transition-colors duration-200 cursor-pointer text-sm tracking-wide"
              >
                <a href={`#${link}`}>{link}</a>
              </li>
            ))}
          </ul>
          <a
            href="/resume.pdf"
            download
            className="flex items-center gap-2 px-5 py-2 rounded-full border border-slate-700 hover:border-blue-500 hover:bg-blue-500/10 text-sm font-medium transition-all duration-300 group"
          >
            Resume
            <MdOutlineFileDownload className="group-hover:translate-y-0.5 transition-transform duration-300" size={18} />
          </a>
        </div>

        <div
          onClick={() => setNav(!nav)}
          className="cursor-pointer z-10 text-slate-400 md:hidden hover:text-white transition-colors"
        >
          {nav ? <FaTimes size={25} /> : <FaBars size={25} />}
        </div>

        {nav && (
          <div className="absolute top-0 left-0 w-full h-screen bg-slate-950 flex flex-col justify-center items-center">
            <ul className="flex flex-col gap-8 text-center">
              {links.map(({ id, link }) => (
                <li
                  key={id}
                  className="capitalize text-3xl font-bold text-slate-400 hover:text-white transition-colors duration-200 cursor-pointer"
                >
                  <a onClick={() => setNav(false)} href={`#${link}`}>
                    {link}
                  </a>
                </li>
              ))}
              <li>
                 <a
                  href="/resume.pdf"
                  download
                  className="flex items-center justify-center gap-2 px-8 py-3 mt-4 rounded-full bg-blue-600 text-white font-medium hover:bg-blue-700 transition-all duration-300"
                >
                  Download Resume
                  <MdOutlineFileDownload size={20} />
                </a>
              </li>
            </ul>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
